import{_ as s,c as i,o as a,a4 as n}from"./chunks/framework.CC18aqI2.js";const E=JSON.parse('{"title":"Spring杂记","description":"","frontmatter":{"prev":false,"next":false},"headers":[],"relativePath":"article/backEnd/Spring/Spring杂记.md","filePath":"article/backEnd/Spring/Spring杂记.md","lastUpdated":null}'),p={name:"article/backEnd/Spring/Spring杂记.md"},t=n(`<h1 id="spring杂记" tabindex="-1">Spring杂记 <a class="header-anchor" href="#spring杂记" aria-label="Permalink to &quot;Spring杂记&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>这部分杂记类似于随笔，并不是系统学习时候的笔记，而是从平时编程碰到的一些问题中总结出来的知识点</p><p>虽然已经系统地学习过了SpringBoot，但是掌握的还不够扎实，通过记笔记📒的方式复习一下</p><h2 id="spring的配置" tabindex="-1">Spring的配置 <a class="header-anchor" href="#spring的配置" aria-label="Permalink to &quot;Spring的配置&quot;">​</a></h2><p>组件的扫描、自动装配、组件管理是Spring框架非常厉害的地方😎</p><p>默认情况下，Spring的启动类只会扫描启动类所在包下的组件</p><p>但是，很多时候，尤其是在微服务的项目架构下，经常要用到跨模块之间的组件调用</p><p>来举个🌰:</p><p>现在在一个电商微服务架构的项目下面有三个模块:</p><ul><li>Common模块，用于定义一些通用的工具类以及各种配置类</li><li>Cart模块，处理一些和电商购物车🛒相关的业务逻辑</li><li>GateWay模块，也就是网关模块，主要处理用户登录，拦截部分请求🫸</li></ul><p>现在我们在Common模块中有一个用于注册全局拦截器的配置类:MvcConfig，代码如下:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Configuration</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MvcConfig</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> implements</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> WebMvcConfigurer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    @</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Override</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> addInterceptors</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(InterceptorRegistry </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">registry</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        registry.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">addInterceptor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> UserInfoInterceptor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">());</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>这个配置类注册了一个全局拦截器实例对象<code>new UserInfoInterceptor()</code></p><p>但是要想让这个全局拦截器实现跨模块拦截，显然一个@Configuration是不够的，它只作用于自己的模块</p><p>因此，为了让其它类也能应用这个拦截器，有如下方案:</p><p>1.在spring.factories中配置一下配置类的包路径</p><p>spring.factories 文件通常位于项目的 META-INF 目录下（例如 src/main/resources/META-INF/spring.factories）</p><p>它定义了一个或多个 Spring Boot 自动配置的实现类。这些实现类会在 Spring Boot 应用程序启动时被自动加载并应用。</p><p>并且作用域是全局的。例如，可以这样书写配置:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>org.springframework.boot.autoconfigure.EnableAutoConfiguration=\\</span></span>
<span class="line"><span>  com.hmall.common.config.MyBatisConfig,\\</span></span>
<span class="line"><span>  com.hmall.common.config.MvcConfig</span></span></code></pre></div><p>写清楚是在哪个包下面的哪个配置类，这样就可以实现将拦截器应用于全局，这种配置方式很高效</p><p>2.用@Import注解导入</p><p>如果要让Cart这个模块也应用这个拦截器，就需要在Cart模块的启动类上进行配置导入:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Configuration</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(com.example.common.config.CommonConfig.class)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SpringBootApplication</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> CartServiceApplication</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // 应用程序入口点</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> static</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">String</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[] </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">args</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        SpringApplication.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">run</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(CartServiceApplication.class, args);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>前提是这个配置类已经用@Configuration标注了才能这样导入</p><p>这种方式比较低效，因为一旦模块多了，每个模块都要导入一遍，效率太低了😭</p><p>3.@ComponentScan注解</p><p>这种方式需要在对应的配置类上面加上注解:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ComponentScan</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.hmall&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.otherpackage&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,……})</span></span></code></pre></div><p>后面要把所有要应用的包全都指定，非常麻烦，效率也很低😣</p><p>⚠️完成上面的步骤之后，还要特别注意网关这个模块</p><p>网关中的拦截器和SpringMVC的拦截器完全不一样，如果这样全局配置也会给网关配置拦截器，会报错</p><p>因为网关模块根本就没有MVC拦截器的内核，这样强行给网关配置没有的东西显然不合适</p><p>因此，配置的时候就要排除网关模块，这里就要用到@ConditionalOnClass(DispatcherServlet.class)</p><p>这个注解条件可以实现筛选，只有拥有DispatcherServlet.class类的模块才能实现配置</p><p>但是上面提到，网关模块是没有这个类的，因为这是SpringMVC的核心类</p><p>所以，还要在配置类上面加上@ComponentScan({&quot;com.hmall&quot;, &quot;com.otherpackage&quot;,……})注解</p>`,38),l=[t];function e(h,k,r,o,c,g){return a(),i("div",null,l)}const y=s(p,[["render",e]]);export{E as __pageData,y as default};
